 15	jest.mock('../../../hooks/use-k8sGet-hook', () => ({
 16	  useK8sGet: jest.fn(),
 17	}));
 18	
 19	const emptyHeaders = new Headers();
 20	const apiResults = ({
 21	  ok,
 22	  status,
 23	  versions,
 24	}: {
 25	  ok: boolean;
 26	  status?: number;
 27	  versions?: TektonHubTaskVersion[];
 28	}) =>
 29	  Promise.resolve({
 30	    headers: emptyHeaders,
 31	    ok,
 32	    ...(status && { status }),
 33	    json: () => ({
 34	      data: {
 35	        versions,
 36	      },
 37	    }),
 38	  });
 39	
 40	// setUtilsConfig({ appFetch: appInternalFetch });
 41	
 42	xdescribe('getApiResponse', () => {
 43	  beforeEach(() => {
 44	    (window as any).fetch = jest.fn(() =>
 45	      apiResults({
 46	        ok: true,
 47	        status: 200,
 48	        versions: sampleTektonHubCatalogItem.attributes.versions,
 49	      }),
 50	    );
 51	    window.console.warn = jest.fn(() => '');
 52	  });
 53	
 54	  afterEach(() => {
 55	    (window.fetch as jest.Mock).mockClear();
 56	    (window.console.warn as jest.Mock).mockClear();
 57	  });
 58	
 59	  it('should throw error if the response status is not 200', async () => {
 60	    (window as any).fetch = jest.fn(() =>
 61	      Promise.resolve({ status: 404, headers: emptyHeaders }),
 62	    );
 63	    try {
 64	      await getApiResponse('testurl');
 65	      fail('Expect an error if the response status is not 200');
 66	    } catch (e) {
 67	      expect(e?.code).toBe(404);
 68	    }
 69	  });
 70	
 71	  it('should throw error if the response ok is false', async () => {
 72	    (window as any).fetch = jest.fn(() =>
 73	      Promise.resolve({ ok: false, status: 500, headers: emptyHeaders }),
 74	    );
 75	
 76	    try {
 77	      await getApiResponse('testurl');
 78	      fail('Expect an error if the response ok is false');
 79	    } catch (e) {
 80	      expect(e?.response?.ok).toBe(false);
 81	    }
 82	  });
 83	
 84	  it('should return a valid response', async () => {
 85	    const response = await getApiResponse('testurl');
 86	    expect(response.data).toBeDefined();
 87	    expect(response.data.versions).toBeDefined();
 88	  });
 89	});
 90	
 91	xdescribe('getHubUIPath', () => {
 92	  it('should return null if the path is not set', () => {
 93	    expect(getHubUIPath('')).toBeNull();
 94	    expect(getHubUIPath(null)).toBeNull();
 95	    expect(getHubUIPath(undefined)).toBeNull();
 96	  });
 97	
 98	  it('should return a value if the path is set', () => {
 99	    expect(getHubUIPath('test')).not.toBeNull();
100	    expect(getHubUIPath('test-path')).toBe(`${TEKTON_HUB_ENDPOINT}/test-path`);
101	  });
102	
103	  it('should return custom path url if the baseurl param is passed as a second argument', () => {
104	    expect(getHubUIPath('test-path', 'https://hub-ui.com')).toBe(
105	      `https://hub-ui.com/test-path`,
106	    );
107	  });
108	});
