110	xdescribe('useInClusterTektonHubURLs:', () => {
111	  it('should return public tekton hub endpoint incase of hub CR not found', async () => {
112	    (useK8sGet as jest.Mock).mockReturnValue([
113	      null,
114	      true,
115	      'error fetching tektonhubs.operator.tekton.dev "hub" not found',
116	    ]);
117	    const { result } = testHook(() => useInclusterTektonHubURLs());
118	    expect(result.current).toEqual({
119	      loaded: true,
120	      apiURL: TEKTON_HUB_API_ENDPOINT,
121	      uiURL: TEKTON_HUB_ENDPOINT,
122	    });
123	  });
124	
125	  it('should return public tekton hub endpoint when hub is installed and if status field missing', async () => {
126	    const sampleHubWithoutApiURL = {
127	      ...sampleTektonHubCR,
128	      status: null,
129	    };
130	    (useK8sGet as jest.Mock).mockReturnValue([
131	      sampleHubWithoutApiURL,
132	      true,
133	      '',
134	    ]);
135	    const { result } = testHook(() => useInclusterTektonHubURLs());
136	    expect(result.current).toEqual({
137	      loaded: true,
138	      apiURL: TEKTON_HUB_API_ENDPOINT,
139	      uiURL: TEKTON_HUB_ENDPOINT,
140	    });
141	  });
142	
143	  it('should return public tekton hub endpoint when hub is installed but urls are missing', async () => {
144	    const sampleHubWithoutApiURL = {
145	      ...sampleTektonHubCR,
146	      status: {
147	        ...sampleTektonHubCR.status,
148	        apiUrl: '',
149	        uiUrl: '',
150	      },
151	    };
152	    (useK8sGet as jest.Mock).mockReturnValue([
153	      sampleHubWithoutApiURL,
154	      true,
155	      '',
156	    ]);
157	    const { result } = testHook(() => useInclusterTektonHubURLs());
158	    expect(result.current).toEqual({
159	      loaded: true,
160	      apiURL: TEKTON_HUB_API_ENDPOINT,
161	      uiURL: TEKTON_HUB_ENDPOINT,
162	    });
163	  });
164	
165	  it('should return incluster tekton hub endpoint when hub is installed', async () => {
166	    (useK8sGet as jest.Mock).mockReturnValue([sampleTektonHubCR, true, '']);
167	    const { result } = testHook(() => useInclusterTektonHubURLs());
168	    expect(result.current).toEqual({
169	      loaded: true,
170	      apiURL: sampleTektonHubCR.status.apiUrl,
171	      uiURL: sampleTektonHubCR.status.uiUrl,
172	    });
173	  });
174	
175	  it('should return the apiUrl and uiUrl when the api call the hub has urls in the status', async () => {
176	    const sampleHubWithoutApiURL = {
177	      ...sampleTektonHubCR,
178	      status: null,
179	    };
180	    (useK8sGet as jest.Mock).mockReturnValue([
181	      sampleHubWithoutApiURL,
182	      true,
183	      '',
184	    ]);
185	    const { result, rerender } = testHook(() => useInclusterTektonHubURLs());
186	    expect(result.current).toEqual({
187	      loaded: true,
188	      apiURL: TEKTON_HUB_API_ENDPOINT,
189	      uiURL: TEKTON_HUB_ENDPOINT,
190	    });
191	
192	    (useK8sGet as jest.Mock).mockReturnValue([sampleTektonHubCR, true, '']);
193	    act(() => {
194	      rerender();
195	    });
196	    expect(result.current).toEqual({
197	      loaded: true,
198	      apiURL: sampleTektonHubCR.status.apiUrl,
199	      uiURL: sampleTektonHubCR.status.uiUrl,
200	    });
201	  });
202	});

